#include <iostream> // For standard input/output operations (cin, cout)
#include <vector>   // For dynamic array (std::vector)
#include <algorithm> // For sorting (std::sort)
#include <functional> // For std::greater (used with sort for descending order)

// Modulo constant for calculations
const int MOD = 1e9 + 7;
// Maximum possible value for n (number of bloggers), used for precomputing factorials
const int MAX_N = 1000;

// Arrays to store precomputed factorials and inverse factorials modulo MOD
long long fact[MAX_N + 1];
long long invFact[MAX_N + 1];

// Function to compute (base^exp) % MOD using binary exponentiation (exponentiation by squaring)
long long power(long long base, long long exp) {
    long long res = 1; // Initialize result
    base %= MOD;       // Ensure base is within modulo range
    while (exp > 0) {
        if (exp % 2 == 1) { // If exponent is odd, multiply result by base
            res = (res * base) % MOD;
        }
        base = (base * base) % MOD; // Square the base
        exp /= 2;                   // Halve the exponent
    }
    return res;
}

// Function to compute modular inverse a^(-1) % MOD using Fermat's Little Theorem
// (a^(MOD-2) % MOD is the inverse of a modulo prime MOD)
long long modInverse(long long n) {
    return power(n, MOD - 2);
}

// Function to compute nCr (n choose r) modulo MOD
long long nCr_mod_p(int n, int r) {
    // If r is out of bounds, there are 0 ways
    if (r < 0 || r > n) return 0;
    // C(n, 0) = 1 and C(n, n) = 1
    if (r == 0 || r == n) return 1;
    // C(n, r) = n! / (r! * (n-r)!) = n! * (r!)^(-1) * ((n-r)!)^(-1) (mod MOD)
    // We use precomputed factorials and inverse factorials
    return (((fact[n] * invFact[r]) % MOD) * invFact[n - r]) % MOD;
}

// Function to precompute factorials and inverse factorials up to MAX_N
void precompute_factorials() {
    fact[0] = 1; // 0! = 1
    // Compute factorials
    for (int i = 1; i <= MAX_N; i++) {
        fact[i] = (fact[i - 1] * i) % MOD;
    }

    // Compute inverse factorial for MAX_N using modular inverse
    invFact[MAX_N] = modInverse(fact[MAX_N]);
    // Compute inverse factorials for i from MAX_N-1 down to 0
    // invFact[i] = invFact[i+1] * (i+1) % MOD
    // This is because (i!)^-1 = ((i+1)! / (i+1))^-1 = ((i+1)!)^-1 * (i+1)
    for (int i = MAX_N - 1; i >= 0; i--) {
        invFact[i] = (invFact[i + 1] * (i + 1)) % MOD;
    }
}

// Function to solve a single test case
void solve() {
    int n, k;
    std::cin >> n >> k; // Read n and k
    std::vector<int> a(n); // Create a vector to store follower counts
    for (int i = 0; i < n; ++i) {
        std::cin >> a[i]; // Read follower counts
    }

    // Sort the follower counts in descending order
    // This helps identify the k largest values easily
    std::sort(a.begin(), a.end(), std::greater<int>());

    // The k-th largest follower count (0-indexed, so a[k-1])
    // This is the minimum follower count among the top k bloggers
    int threshold_val = a[k - 1];

    // Count the total number of bloggers who have 'threshold_val' followers
    int total_threshold_count = 0;
    for (int x : a) {
        if (x == threshold_val) {
            total_threshold_count++;
        }
    }

    // Count how many bloggers among the *top k* (i.e., a[0] to a[k-1])
    // have 'threshold_val' followers.
    // These are the bloggers with 'threshold_val' followers that *must* be chosen
    // to achieve the maximum sum.
    int required_threshold_count = 0;
    for (int i = 0; i < k; ++i) {
        if (a[i] == threshold_val) {
            required_threshold_count++;
        }
    }

    // The number of ways to select k bloggers for maximum total followers
    // is C(total_bloggers_with_threshold_val, bloggers_with_threshold_val_in_top_k).
    // This is because all bloggers with followers > threshold_val are fixed.
    // We need to pick 'required_threshold_count' bloggers from 'total_threshold_count' available
    // bloggers, all having 'threshold_val' followers.
    std::cout << nCr_mod_p(total_threshold_count, required_threshold_count) << std::endl;
}

int main() {
    // Optimize C++ standard streams for faster input/output.
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);

    // Precompute factorials and inverse factorials once before all test cases
    precompute_factorials();

    int t;
    std::cin >> t; // Read the number of test cases
    while (t--) {
        solve(); // Solve each test case
    }

    return 0;
}

